quick_practical_examples.code:
class Person:
    def __init__(self, name):
        self.name = name

class Student(Person):
    def __init__(self, name, grade):
        super().__init__(name)
        self.grade = grade

s = Student("أحمد", "ممتاز")
print(s.name, s.grade)

class Bird:
    def fly(self):
        print("يطير")

class Penguin(Bird):
    def swim(self):
        print("يسبح")

p = Penguin()
p.fly() # لا خطأ برمجي، ولكن البطريق لا يطير!

class Vehicle:
    def __init__(self):
        self.wheels = 4

class Motorcycle(Vehicle):
    def __init__(self):
        # ينقص هنا استدعاء الأب لتعيين عدد العجلات
        self.wheels = 2

m = Motorcycle()
print(m.wheels)

